import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterOutlet, RouterLink, RouterLinkActive } from '@angular/router';
import { AuthService } from '../core/services/auth.service';

interface NavItem {
  label: string;
  icon: string;
  link: string;
  admin?: boolean;
}

/**
 * Authenticated EasyFile shell: brand header + top nav on desktop,
 * a fixed bottom tab bar on mobile (≤768px). Admin items appear only for admins.
 * SMOKE_MARKER: EasyFile
 */
@Component({
  selector: 'app-layout',
  standalone: true,
  imports: [CommonModule, RouterOutlet, RouterLink, RouterLinkActive],
  templateUrl: './layout.component.html',
  styleUrl: './layout.component.css',
})
export class LayoutComponent {
  readonly navItems: NavItem[] = [
    { label: 'Returns', icon: '📄', link: '/returns' },
    { label: 'Stats', icon: '📊', link: '/admin/stats', admin: true },
    { label: 'Users', icon: '👥', link: '/admin/users', admin: true },
    { label: 'Settings', icon: '⚙️', link: '/admin/settings', admin: true },
  ];

  constructor(public auth: AuthService) {}

  get visibleItems(): NavItem[] {
    return this.navItems.filter((i) => !i.admin || this.auth.isAdmin());
  }

  logout(): void {
    this.auth.logout();
  }
}
